11	__global__ void __launch_bounds__(32, 1, 1)
12	get_mla_metadata_kernel(__grid_constant__ const GetDecodeSchedMetaParams params) {
13	    int *seqlens_k_ptr = params.seqlens_k_ptr;
14	    DecodingSchedMeta *tile_scheduler_metadata_ptr = params.tile_scheduler_metadata_ptr;
15	    int *num_splits_ptr = params.num_splits_ptr;
16	    int batch_size = params.b;
17	    int block_size_n = params.block_size_n;
18	    int fixed_overhead_num_blocks = params.fixed_overhead_num_blocks;
19	    int num_sm_parts = params.num_sm_parts;
20	
21	    extern __shared__ int shared_mem[];
22	    int* num_blocks_shared = shared_mem; // [batch_size]
23	    int* num_splits_shared = shared_mem + batch_size; // [batch_size+1]
24	    int* seqlens_k_shared = shared_mem + batch_size*2+1; // [batch_size]
25	    int* first_block_idx_shared = shared_mem + batch_size*3+1; // [batch_size]
26	    int* last_block_idx_shared = shared_mem + batch_size*4+1; // [batch_size]
27	
28	    int total_num_blocks = 0;
29	    for (int i = threadIdx.x; i < batch_size; i += 32) {
30	        int cur_s_k;
31	        if (params.topk == -1) {
32	            // Dense model, cur_s_k = actual s_k
33	            cur_s_k = __ldg(seqlens_k_ptr + i);
34	        } else {
35	            // Sparse model, cur_s_k = topk (+ extra topk)
36	            cur_s_k = params.topk_length ? __ldg(params.topk_length + i) : params.topk;
37	            if (cur_s_k == 0) cur_s_k = 1;  // Ensure the main loop will never be empty
38	            if (params.extra_topk) {
39	                cur_s_k = ku::ceil(cur_s_k, block_size_n);
40	                cur_s_k += params.extra_topk_length ? __ldg(params.extra_topk_length + i) : params.extra_topk;
41	            }
42	        }
43	        seqlens_k_shared[i] = cur_s_k;
44	        int first_token_idx = 0;
45	        int last_token_idx = max(cur_s_k-1, 0);
46	        int cur_first_block_idx = first_token_idx / block_size_n;
47	        int cur_last_block_idx = last_token_idx / block_size_n;
48	        // NOTE Should attend to tokens [first_token_idx, last_token_idx], i.e. blocks [cur_first_block_idx, cur_last_block_idx]
49	        // NOTE if seqlens_k is 0, then first_token_idx == last_token_idx == cur_first_block_idx == cur_last_block_idx == 0. So the sequence will have 1 block. We will correct this later in this kernel.
50	        int num_blocks = cur_last_block_idx - cur_first_block_idx + 1;
51	        total_num_blocks += num_blocks + fixed_overhead_num_blocks;
52	        num_blocks_shared[i] = num_blocks;
53	        first_block_idx_shared[i] = cur_first_block_idx;
54	        last_block_idx_shared[i] = cur_last_block_idx;
55	    }
56	    for (int offset = 16; offset >= 1; offset /= 2) {
57	        total_num_blocks += __shfl_xor_sync(uint32_t(-1), total_num_blocks, offset);
58	    }
59	    __syncwarp();
60	
61	    if (threadIdx.x == 0) {
62	        int payload = cutlass::ceil_div(total_num_blocks, num_sm_parts) + fixed_overhead_num_blocks;
63	
64	        int now_req_idx = 0, now_block = 0, now_n_split_idx = 0, cum_num_splits = 0;
65	        num_splits_shared[0] = 0;
66	        for (int i = 0; i < num_sm_parts; ++i) {
67	            DecodingSchedMeta cur_meta;
68	            cur_meta.begin_req_idx = now_req_idx;
69	            cur_meta.begin_block_idx = now_block + first_block_idx_shared[now_req_idx];
70	            cur_meta.begin_split_idx = now_n_split_idx;
71	            cur_meta.is_first_req_splitted = (now_block != 0);
72	            int remain_payload = payload;
73	            while (now_req_idx < batch_size) {
74	                int num_blocks = num_blocks_shared[now_req_idx];
75	                int now_remain_blocks = num_blocks - now_block;
76	                if (remain_payload >= now_remain_blocks + fixed_overhead_num_blocks) {
77	                    cum_num_splits += now_n_split_idx + 1;
78	                    num_splits_shared[now_req_idx + 1] = cum_num_splits;
79	                    remain_payload -= now_remain_blocks + fixed_overhead_num_blocks;
80	                    ++now_req_idx;
81	                    now_block = 0;
82	                    now_n_split_idx = 0;
83	                } else {
84	                    if (remain_payload - fixed_overhead_num_blocks > 0) {
85	                        now_block += remain_payload - fixed_overhead_num_blocks;
86	                        ++now_n_split_idx;
87	                        remain_payload = 0;
88	                    }
89	                    break;
90	                }
91	            }
92	            cur_meta.end_req_idx = now_block > 0 ? now_req_idx : now_req_idx - 1;
93	            cur_meta.end_block_idx = now_block > 0 ? now_block + first_block_idx_shared[now_req_idx] : (seqlens_k_shared[now_req_idx-1] == 0 ? 0 : last_block_idx_shared[now_req_idx-1] + 1);
94	            cur_meta.is_last_req_splitted = cur_meta.end_block_idx != last_block_idx_shared[cur_meta.end_req_idx] + 1 && seqlens_k_shared[cur_meta.end_req_idx] != 0;
95	            if (cur_meta.begin_req_idx == cur_meta.end_req_idx) {
96	                cur_meta.is_first_req_splitted = cur_meta.is_last_req_splitted = cur_meta.is_first_req_splitted || cur_meta.is_last_req_splitted;
97	            }
98	            tile_scheduler_metadata_ptr[i] = cur_meta;
99	        }
100	        FLASH_DEVICE_ASSERT(now_req_idx == batch_size && now_block == 0 && now_n_split_idx == 0);
101	    }
102	    __syncwarp();
103	
104	    for (int i = threadIdx.x; i <= batch_size; i += 32) {
105	        num_splits_ptr[i] = num_splits_shared[i];
106	    }
107	}
